import './Main.css'
import POST from '../Post/Post'
import React, { Component } from 'react'

export default class Main extends Component {

    openWindPots = (id) => {
        this.props.openWindPots(id)
    }

    render() {
        const { list, tag, listVisible, listVisibleForTitle } = this.props
        let array = []

        function params(index, i) {
            return list[i].tags.indexOf(tag.split(",")[index]) !== -1
        }

        if (listVisible.length === 0) {
            for (let i = 0; i < list.length; i++) {
                array.push(<POST key={list[i].id} openWindPots={this.openWindPots} list={list[i]} />)
            }
        } else if (tag !== null) {
            for (let i = 0; i < list.length; i++) {
                if ((params(0, i) || params(1, i) || params(2, i) || params(3, i))) {
                    array.push(
                        <POST key={this.props.list[i].id} openWindPots={this.openWindPots} list={this.props.list[i]} />
                    )
                }
            }
        } else {
            for (let i = 0; i < list.length; i++) {
                if (list[i].tags.indexOf(listVisible.toLowerCase()) !== -1) {
                    array.push(<POST key={list[i].id} openWindPots={this.openWindPots} list={list[i]} />)
                }
            }
        }

        return (
            <div className="main-block">
                {array}
            </div>
        )
    }
}
